const fs = require('fs');
const path = require('path');

const PAPERS_DIR = '/app/papers';
const DRUGS_FILE = '/app/term_banks/drugs.txt';
const PHENOS_FILE = '/app/term_banks/phenotypes.txt';
const TARGET_ALLELES = new Set(['1','4','5','6','17','40']);

function readList(p) {
  return fs.readFileSync(p, 'utf8')
    .split(/\r?\n/)
    .map(s => s.trim().toLowerCase())
    .filter(s => s && !s.startsWith('#'));
}

const drugs = new Set(readList(DRUGS_FILE));
const phenos = new Set(readList(PHENOS_FILE));

const alleleRegex = new RegExp(String.raw`\bCYP2D6\s*\*(?:${Array.from(TARGET_ALLELES).sort((a,b)=>b.length-a.length).join('|')})\b`, 'i');
const starOnlyRegex = new RegExp(String.raw`(\*(?:${Array.from(TARGET_ALLELES).sort((a,b)=>b.length-a.length).join('|')}))\b`);
const cyp2d6Regex = /cyp\s*2d6/i;

function isRelevant(text){
  if (alleleRegex.test(text)) return true;
  const paras = text.split(/\n\s*\n/);
  for (const p of paras){
    if (cyp2d6Regex.test(p) && starOnlyRegex.test(p)) return true;
  }
  return false;
}

function findMatches(text, items){
  const out = new Set();
  for (const item of items){
    if (item.length < 3) continue;
    const pat = new RegExp(`(?<![a-z0-9])${item.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}(?![a-z0-9])`, 'i');
    if (pat.test(text)) out.add(item);
  }
  return out;
}

const files = fs.readdirSync(PAPERS_DIR).filter(f=>f.endsWith('.md')).sort();
const relevant = [];
let foundDrugs = new Set();
let foundPhenos = new Set();

for (const f of files){
  const p = path.join(PAPERS_DIR, f);
  const text = fs.readFileSync(p, 'utf8');
  if (!isRelevant(text)) continue;
  relevant.push(f);
  const paras = text.split(/\n\s*\n/).filter(p=>cyp2d6Regex.test(p));
  const parasWithAllele = paras.filter(p=>starOnlyRegex.test(p) || alleleRegex.test(p));
  const targetParas = (parasWithAllele.length ? parasWithAllele : paras).join('\n').toLowerCase();
  const d = findMatches(targetParas, drugs);
  const ph = findMatches(targetParas, phenos);
  d.forEach(x=>foundDrugs.add(x));
  ph.forEach(x=>foundPhenos.add(x));
}

// Phenotype category: efficacy → prefer 'pain' if present
const selectedPhenos = [];
if (foundPhenos.has('pain')) selectedPhenos.push('pain');

const out = {
  drugs: Array.from(foundDrugs).sort(),
  phenotypes: selectedPhenos,
  relevant_paper_count: new Set(relevant).size,
};

console.error('Relevant files:', relevant);
console.log(JSON.stringify(out, null, 2));
